package genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_summary.service.VehicleDailySummaryService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/daily-summaries") public class VehicleDailySummaryController { private final VehicleDailySummaryService service; public VehicleDailySummaryController(VehicleDailySummaryService service){this.service=service;} @GetMapping public List<VehicleDailySummaryResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleDailySummaryResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleDailySummaryResponse create(@RequestBody VehicleDailySummaryUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleDailySummaryResponse update(@PathVariable UUID id,@RequestBody VehicleDailySummaryUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
